import { boolean, jsonb, pgTable, text, timestamp, uuid } from "drizzle-orm/pg-core";

export const featureFlags = pgTable("feature_flags", {
  id: uuid("id").primaryKey().defaultRandom(),
  key: text("key").notNull().unique(),
  description: text("description"),
  enabled: boolean("enabled").notNull().default(false),
  rules: jsonb("rules").$type<Array<{ organizationId?: string; percentage?: number }>>().notNull().default([]),
  createdAt: timestamp("created_at", { withTimezone: true }).defaultNow().notNull(),
  updatedAt: timestamp("updated_at", { withTimezone: true }).defaultNow().notNull(),
});

import "server-only";

export type FeatureFlag = {
  key: string;
  enabled: boolean;
  rules?: Array<{ organizationId?: string; percentage?: number }>;
};

export type FeatureFlagContext = {
  organizationId?: string;
  stableId?: string;
};

export function evaluateFeatureFlag(flag: FeatureFlag | undefined, context: FeatureFlagContext = {}) {
  if (!flag?.enabled) return false;
  if (!flag.rules?.length) return true;

  return flag.rules.some((rule) => {
    if (rule.organizationId) return rule.organizationId === context.organizationId;
    if (typeof rule.percentage === "number" && context.stableId) {
      return bucketStableId(context.stableId, flag.key) < rule.percentage;
    }
    return false;
  });
}

function bucketStableId(stableId: string, salt: string) {
  let hash = 0;
  for (const char of salt + ":" + stableId) hash = (hash * 31 + char.charCodeAt(0)) >>> 0;
  return hash % 100;
}

const flags = [
  { key: "new_onboarding", enabled: true, scope: "20% rollout" },
  { key: "admin_console_v2", enabled: false, scope: "staff only" },
];

export default function FeatureFlagsPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">Feature Flags</h1>
        <p className="text-muted-foreground">Control progressive rollouts without adding a provider dependency.</p>
      </div>
      <div className="grid gap-3">
        {flags.map((flag) => (
          <div key={flag.key} className="flex items-center justify-between rounded-lg border p-4">
            <div>
              <p className="font-medium">{flag.key}</p>
              <p className="text-sm text-muted-foreground">{flag.scope}</p>
            </div>
            <span className="text-sm">{flag.enabled ? "Enabled" : "Disabled"}</span>
          </div>
        ))}
      </div>
    </main>
  );
}
